# WorldGen: From Text to Traversable and Interactive 3D Worlds

## Introduction

WorldGen presents a breakthrough approach to generating fully traversable and interactive 3D worlds from natural language descriptions. Rather than static scene images, this system creates immersive 3D environments where users can navigate, interact with objects, and experience spatial reasoning. The work bridges the gap between language understanding and 3D environment synthesis, enabling the creation of complex virtual worlds guided purely by text input.

## Core Insight

The fundamental insight is that 3D world generation can be decomposed into: (1) semantic scene understanding from text, (2) spatial layout planning, (3) asset placement and composition, and (4) interactive property assignment. By treating world generation as a sequential decision-making process with hierarchical scene graphs, WorldGen creates coherent, navigable environments that maintain semantic consistency with the text description while supporting user interaction and exploration.

## Implementation

```python
import numpy as np
from typing import List, Dict, Tuple
import json

class WorldGenerator:
    """Generate traversable 3D worlds from text descriptions."""

    def __init__(self, model_path: str = "worldgen-base"):
        self.model_path = model_path
        self.semantic_parser = SemanticParser()
        self.layout_planner = LayoutPlanner()
        self.asset_composer = AssetComposer()
        self.physics_engine = PhysicsEngine()

    def parse_description(self, text: str) -> Dict:
        """Parse natural language description into semantic structure."""
        entities = self.semantic_parser.extract_entities(text)
        relationships = self.semantic_parser.extract_spatial_relations(text)
        interactions = self.semantic_parser.extract_interactions(text)

        return {
            "entities": entities,
            "relationships": relationships,
            "interactions": interactions,
            "raw_text": text
        }

    def plan_layout(self, semantics: Dict) -> np.ndarray:
        """Plan 3D spatial layout from semantic structure."""
        # Initialize scene bounds
        scene_bounds = np.array([[-100, -100, 0], [100, 100, 100]])

        # Place entities with spatial constraints
        positions = {}
        for entity in semantics["entities"]:
            # Determine size category and placement strategy
            size_class = self._classify_entity_size(entity)
            pos = self.layout_planner.find_placement(
                entity, size_class, positions, semantics["relationships"]
            )
            positions[entity["id"]] = pos

        # Enforce spatial relationships
        for rel in semantics["relationships"]:
            self._enforce_relationship(rel, positions)

        return positions

    def compose_assets(self, semantics: Dict, positions: Dict) -> List[Dict]:
        """Compose 3D assets into world structure."""
        assets = []

        for entity in semantics["entities"]:
            # Select appropriate asset variants
            asset_variants = self.asset_composer.get_variants(
                entity["type"], entity.get("properties", {})
            )

            selected_asset = self.asset_composer.select_variant(
                asset_variants, entity.get("style_hints", "default")
            )

            asset_object = {
                "id": entity["id"],
                "type": entity["type"],
                "model": selected_asset["path"],
                "position": positions[entity["id"]].tolist(),
                "rotation": self._compute_rotation(entity),
                "scale": self._compute_scale(entity),
                "material": selected_asset.get("material", "default"),
                "interactive": entity.get("interactive", False),
                "properties": entity.get("properties", {})
            }

            assets.append(asset_object)

        return assets

    def assign_interactions(self, assets: List[Dict], semantics: Dict) -> List[Dict]:
        """Assign interactive properties and behaviors."""
        for asset in assets:
            # Find interactions involving this asset
            relevant_interactions = [
                i for i in semantics.get("interactions", [])
                if asset["id"] in i.get("entities", [])
            ]

            if relevant_interactions:
                asset["interactive"] = True
                asset["behaviors"] = []

                for interaction in relevant_interactions:
                    behavior = {
                        "type": interaction["action"],
                        "trigger": interaction.get("trigger_type", "proximity"),
                        "response": interaction.get("response", {}),
                        "conditions": interaction.get("conditions", [])
                    }
                    asset["behaviors"].append(behavior)

        return assets

    def generate_world(self, text_description: str) -> Dict:
        """Generate complete traversable 3D world from text."""
        # Parse input
        semantics = self.parse_description(text_description)

        # Plan spatial layout
        positions = self.plan_layout(semantics)

        # Compose assets
        assets = self.compose_assets(semantics, positions)

        # Assign interactions
        assets = self.assign_interactions(assets, semantics)

        # Build scene graph
        world = {
            "version": "1.0",
            "description": text_description,
            "bounds": [[-100, -100, 0], [100, 100, 100]],
            "assets": assets,
            "semantics": semantics,
            "traversable": True,
            "collision_enabled": True,
            "gravity": [0, 0, -9.81]
        }

        return world

    def export_world(self, world: Dict, format: str = "gltf") -> str:
        """Export world to standard 3D format."""
        if format == "gltf":
            return self._export_gltf(world)
        elif format == "usdz":
            return self._export_usdz(world)
        else:
            return self._export_json(world)

    def _classify_entity_size(self, entity: Dict) -> str:
        """Classify entity size category."""
        size_hints = entity.get("size", "medium")
        return size_hints

    def _compute_rotation(self, entity: Dict) -> List[float]:
        """Compute 3D rotation from semantic properties."""
        return entity.get("rotation", [0, 0, 0])

    def _compute_scale(self, entity: Dict) -> List[float]:
        """Compute scale from entity properties."""
        return entity.get("scale", [1.0, 1.0, 1.0])

